  1→import type {
  2→  SDUIActionHandler,
  3→  SDUIActionResult,
  4→  SDUIArithmeticExpression,
  5→} from '../models';
  6→import { evaluateExpression } from '../utils/jsonLogic';
  7→import { resolveContextPath } from '../utils/interpolation';
  8→
  9→function setAtPath(
 10→  obj: Record<string, unknown>,
 11→  path: string,
 12→  value: unknown,
 13→): Record<string, unknown> {
 14→  const segments = path.split('.');
 15→  if (segments.length === 1) {
 16→    return { ...obj, [segments[0]]: value };
 17→  }
 18→
 19→  const [head, ...rest] = segments;
 20→  const child = (obj[head] ?? {}) as Record<string, unknown>;
 21→  return {
 22→    ...obj,
 23→    [head]: setAtPath(
 24→      typeof child === 'object' && child !== null
 25→        ? { ...child }
 26→        : {},
 27→      rest.join('.'),
 28→      value,
 29→    ),
 30→  };
 31→}
 32→
 33→function getAtPath(
 34→  obj: Record<string, unknown>,
 35→  path: string,
 36→): unknown {
 37→  const resolved = resolveContextPath(
 38→    obj as Parameters<typeof resolveContextPath>[0],
 39→    path,
 40→  );
 41→  return resolved;
 42→}
 43→
 44→export const setValueHandler: SDUIActionHandler = (
 45→  payload,
 46→  actionContext,
 47→): SDUIActionResult => {
 48→  if (!payload?.contextKey || typeof payload.contextKey !== 'string') {
 49→    return { success: false, error: 'setValue requires a "contextKey" string in payload' };
 50→  }
 51→
 52→  if (!('value' in payload)) {
 53→    return { success: false, error: 'setValue requires a "value" in payload' };
 54→  }
 55→
 56→  actionContext.setForm(prev =>
 57→    setAtPath(prev, payload.contextKey as string, payload.value),
 58→  );
 59→
 60→  return { success: true };
 61→};
 62→
 63→export const setComputedHandler: SDUIActionHandler = (
 64→  payload,
 65→  actionContext,
 66→): SDUIActionResult => {
 67→  if (!payload?.contextKey || typeof payload.contextKey !== 'string') {
 68→    return { success: false, error: 'setComputed requires a "contextKey" string in payload' };
 69→  }
 70→
 71→  if (!payload.formula || typeof payload.formula !== 'object') {
 72→    return { success: false, error: 'setComputed requires a "formula" object in payload' };
 73→  }
 74→
 75→  const mergedContext = {
 76→    ...actionContext.screen,
 77→    form: actionContext.form as Parameters<typeof evaluateExpression>[1],
 78→  };
 79→
 80→  const computed = evaluateExpression(
 81→    payload.formula as SDUIArithmeticExpression,
 82→    mergedContext,
 83→  );
 84→
 85→  actionContext.setForm(prev =>
 86→    setAtPath(prev, payload.contextKey as string, computed),
 87→  );
 88→
 89→  return { success: true, data: computed };
 90→};
 91→
 92→export const useAllHandler: SDUIActionHandler = (
 93→  payload,
 94→  actionContext,
 95→): SDUIActionResult => {
 96→  if (!payload?.sourceKey || typeof payload.sourceKey !== 'string') {
 97→    return { success: false, error: 'useAll requires a "sourceKey" string in payload' };
 98→  }
 99→
100→  if (!payload?.targetKey || typeof payload.targetKey !== 'string') {
101→    return { success: false, error: 'useAll requires a "targetKey" string in payload' };
102→  }
103→
104→  const mergedContext = {
105→    ...actionContext.screen,
106→    form: actionContext.form,
107→  };
108→
109→  const sourceValue = getAtPath(
110→    mergedContext as Record<string, unknown>,
111→    payload.sourceKey as string,
112→  );
113→
114→  actionContext.setForm(prev =>
115→    setAtPath(prev, payload.targetKey as string, sourceValue),
116→  );
117→
118→  return { success: true, data: sourceValue };
119→};
