  1→import type {
  2→  SDUIActionDescriptor,
  3→  SDUIActionContext,
  4→  SDUIActionDeps,
  5→  SDUIActionHandler,
  6→  SDUIActionRegistry,
  7→  SDUIActionResult,
  8→  SDUIContext,
  9→} from '../models';
 10→import { interpolateDeep } from '../utils/interpolation';
 11→import {
 12→  navigateHandler,
 13→  goBackHandler,
 14→  replaceHandler,
 15→  deepLinkHandler,
 16→} from './navigation';
 17→import {
 18→  setValueHandler,
 19→  setComputedHandler,
 20→  useAllHandler,
 21→} from './formState';
 22→
 23→const ANALYTICS_ACTIONS: ReadonlySet<string> = new Set([
 24→  'trackScreenView',
 25→  'trackSelect',
 26→  'trackModalView',
 27→]);
 28→
 29→export function createActionRegistry(
 30→  initial?: SDUIActionRegistry,
 31→): SDUIActionRegistry {
 32→  return { ...initial };
 33→}
 34→
 35→export function registerAction(
 36→  registry: SDUIActionRegistry,
 37→  type: string,
 38→  handler: SDUIActionHandler,
 39→): SDUIActionRegistry {
 40→  return { ...registry, [type]: handler };
 41→}
 42→
 43→export function getActionHandler(
 44→  registry: SDUIActionRegistry,
 45→  type: string,
 46→): SDUIActionHandler | undefined {
 47→  return registry[type];
 48→}
 49→
 50→function buildMergedContext(actionContext: SDUIActionContext): SDUIContext {
 51→  return {
 52→    ...actionContext.screen,
 53→    form: actionContext.form as unknown as SDUIContext,
 54→  };
 55→}
 56→
 57→export async function executeAction(
 58→  registry: SDUIActionRegistry,
 59→  descriptor: SDUIActionDescriptor,
 60→  actionContext: SDUIActionContext,
 61→  deps: SDUIActionDeps,
 62→): Promise<SDUIActionResult> {
 63→  const handler = registry[descriptor.type];
 64→  if (!handler) {
 65→    if (__DEV__) {
 66→      console.warn(`[SDUI] Unknown action type: "${descriptor.type}"`);
 67→    }
 68→    return { success: false, error: `Unknown action type: "${descriptor.type}"` };
 69→  }
 70→
 71→  const mergedContext = buildMergedContext(actionContext);
 72→  const interpolatedPayload = descriptor.payload
 73→    ? interpolateDeep(descriptor.payload, mergedContext)
 74→    : undefined;
 75→
 76→  try {
 77→    return await handler(interpolatedPayload, actionContext, deps);
 78→  } catch (err) {
 79→    const message = err instanceof Error ? err.message : String(err);
 80→    if (__DEV__) {
 81→      console.error(`[SDUI] Action "${descriptor.type}" threw:`, message);
 82→    }
 83→    return { success: false, error: message };
 84→  }
 85→}
 86→
 87→export async function executeActions(
 88→  registry: SDUIActionRegistry,
 89→  descriptors: SDUIActionDescriptor[],
 90→  actionContext: SDUIActionContext,
 91→  deps: SDUIActionDeps,
 92→): Promise<SDUIActionResult[]> {
 93→  const results: SDUIActionResult[] = new Array(descriptors.length);
 94→
 95→  const analyticsIndices: number[] = [];
 96→  const primaryIndices: number[] = [];
 97→
 98→  for (let i = 0; i < descriptors.length; i++) {
 99→    if (ANALYTICS_ACTIONS.has(descriptors[i].type)) {
100→      analyticsIndices.push(i);
101→    } else {
102→      primaryIndices.push(i);
103→    }
104→  }
105→
106→  for (const i of primaryIndices) {
107→    if (deps.signal?.aborted) {
108→      results[i] = { success: false, error: 'Aborted' };
109→      continue;
110→    }
111→    results[i] = await executeAction(registry, descriptors[i], actionContext, deps);
112→  }
113→
114→  for (const i of analyticsIndices) {
115→    results[i] = await executeAction(registry, descriptors[i], actionContext, deps);
116→  }
117→
118→  return results;
119→}
120→
121→const defaultActionRegistry: SDUIActionRegistry = {
122→  navigate: navigateHandler,
123→  goBack: goBackHandler,
124→  replace: replaceHandler,
125→  deepLink: deepLinkHandler,
126→  setValue: setValueHandler,
127→  setComputed: setComputedHandler,
128→  useAll: useAllHandler,
129→};
130→
131→export function getDefaultActionRegistry(): SDUIActionRegistry {
132→  return defaultActionRegistry;
133→}
134→
135→export function registerToDefaultActions(
136→  type: string,
137→  handler: SDUIActionHandler,
138→): void {
139→  defaultActionRegistry[type] = handler;
140→}
