  1→import React, { useState, useCallback, useRef } from 'react';
  2→import { View, ScrollView } from 'react-native';
  3→import { Text, Box, Button, SeparatorHorizontal } from '@semparar/design-system-app';
  4→import type { Meta, StoryObj } from 'storybook/internal/types';
  5→import type { SDUIActionDescriptor, SDUIActionContext, SDUIActionDeps } from '../services/sdui/models';
  6→import {
  7→  executeAction,
  8→  getDefaultActionRegistry,
  9→} from '../services/sdui/actions';
 10→
 11→interface ActionLogEntry {
 12→  id: number;
 13→  type: string;
 14→  payload?: Record<string, unknown>;
 15→  result: { success: boolean; error?: string; data?: unknown };
 16→  timestamp: string;
 17→}
 18→
 19→function FormStateActionsDemo() {
 20→  const [log, setLog] = useState<ActionLogEntry[]>([]);
 21→  const [formState, setFormState] = useState<Record<string, unknown>>({});
 22→  const idRef = useRef(0);
 23→
 24→  const registry = useRef(getDefaultActionRegistry()).current;
 25→
 26→  const actionContext: SDUIActionContext = {
 27→    screen: {
 28→      balance: { pointsQuantity: 15320 } as Record<string, unknown>,
 29→      conversion: { factor: 0.01 } as Record<string, unknown>,
 30→    },
 31→    form: formState,
 32→    setForm: (updater) => {
 33→      setFormState(prev => {
 34→        const next = updater(prev);
 35→        return next;
 36→      });
 37→    },
 38→  };
 39→
 40→  const deps: SDUIActionDeps = {};
 41→
 42→  const fire = useCallback(async (descriptor: SDUIActionDescriptor) => {
 43→    const ctx: SDUIActionContext = {
 44→      ...actionContext,
 45→      form: formState,
 46→      setForm: (updater) => {
 47→        setFormState(prev => {
 48→          const next = updater(prev);
 49→          return next;
 50→        });
 51→      },
 52→    };
 53→
 54→    const result = await executeAction(registry, descriptor, ctx, deps);
 55→    idRef.current += 1;
 56→    const entry: ActionLogEntry = {
 57→      id: idRef.current,
 58→      type: descriptor.type,
 59→      payload: descriptor.payload,
 60→      result: { success: result.success, error: result.error, data: result.data },
 61→      timestamp: new Date().toLocaleTimeString(),
 62→    };
 63→    setLog(prev => [entry, ...prev].slice(0, 20));
 64→  }, [formState]);
 65→
 66→  return (
 67→    <ScrollView style={{ flex: 1 }}>
 68→      <Box p="xxxs">
 69→        <Text type="headingMDL" mb="nano">
 70→          SDUI Form State Actions
 71→        </Text>
 72→        <Text type="bodySM" color="INTENSE_COLOR_03" mb="xs">
 73→          Demonstrates setValue, setComputed, and useAll action handlers.
 74→          Form state is displayed live below.
 75→        </Text>
 76→
 77→        <View style={{
 78→          backgroundColor: '#F5F5F5',
 79→          borderRadius: 8,
 80→          padding: 12,
 81→          marginBottom: 16,
 82→        }}>
 83→          <Text type="subtitleXXL" mb="nano">Form State (live)</Text>
 84→          <Text type="bodySM" style={{ fontFamily: 'monospace' }}>
 85→            {JSON.stringify(formState, null, 2) || '{}'}
 86→          </Text>
 87→        </View>
 88→
 89→        <View style={{
