 6→export const navigateHandler: SDUIActionHandler = (
 7→  payload,
 8→  _actionContext,
 9→  deps,
10→): SDUIActionResult => {
11→  if (!deps.navigation) {
12→    return { success: false, error: 'Navigation dependency not provided' };
13→  }
14→  if (!payload?.screen || typeof payload.screen !== 'string') {
15→    return { success: false, error: 'Navigate action requires a "screen" string in payload' };
16→  }
17→  deps.navigation.navigate(
18→    payload.screen,
19→    payload.params as Record<string, unknown> | undefined,
20→  );
21→  return { success: true };
22→};
23→
24→export const goBackHandler: SDUIActionHandler = (
25→  _payload,
26→  _actionContext,
27→  deps,
28→): SDUIActionResult => {
29→  if (!deps.navigation) {
30→    return { success: false, error: 'Navigation dependency not provided' };
31→  }
32→  deps.navigation.goBack();
33→  return { success: true };
34→};
35→
36→export const replaceHandler: SDUIActionHandler = (
37→  payload,
38→  _actionContext,
39→  deps,
40→): SDUIActionResult => {
41→  if (!deps.navigation) {
42→    return { success: false, error: 'Navigation dependency not provided' };
43→  }
44→  if (!payload?.screen || typeof payload.screen !== 'string') {
45→    return { success: false, error: 'Replace action requires a "screen" string in payload' };
46→  }
47→  deps.navigation.replace(
48→    payload.screen,
49→    payload.params as Record<string, unknown> | undefined,
50→  );
51→  return { success: true };
52→};
53→
54→export const deepLinkHandler: SDUIActionHandler = (
55→  payload,
56→  _actionContext,
57→  deps,
58→): SDUIActionResult => {
59→  if (!deps.linking) {
60→    return { success: false, error: 'Linking dependency not provided' };
61→  }
62→  if (!payload?.url || typeof payload.url !== 'string') {
63→    return { success: false, error: 'DeepLink action requires a "url" string in payload' };
64→  }
65→  deps.linking.openURL(payload.url);
66→  return { success: true };
67→};
