  1→import type {
  2→  SDUIContext,
  3→  SDUIRule,
  4→  SDUIVarOperator,
  5→  SDUILogicPrimitive,
  6→  SDUIExpressionOperand,
  7→  SDUIArithmeticExpression,
  8→} from '../models';
  9→import { resolveContextPath } from './interpolation';
 10→
 11→const MAX_DEPTH = 20;
 12→
 13→const COMPARISON_OPS = new Set(['==', '!=', '>', '<', '>=', '<=']);
 14→const ARITHMETIC_OPS = new Set(['+', '-', '*', '/', 'min', 'max']);
 15→
 16→function isVarOperator(operand: unknown): operand is SDUIVarOperator {
 17→  return (
 18→    operand !== null &&
 19→    typeof operand === 'object' &&
 20→    'var' in operand &&
 21→    typeof (operand as SDUIVarOperator).var === 'string'
 22→  );
 23→}
 24→
 25→function isPrimitive(value: unknown): value is SDUILogicPrimitive {
 26→  return (
 27→    value === null ||
 28→    typeof value === 'string' ||
 29→    typeof value === 'number' ||
 30→    typeof value === 'boolean'
 31→  );
 32→}
 33→
 34→function isArithmeticExpression(value: unknown): value is SDUIArithmeticExpression {
 35→  if (!value || typeof value !== 'object') return false;
 36→  const keys = Object.keys(value);
 37→  return keys.length === 1 && ARITHMETIC_OPS.has(keys[0]);
 38→}
 39→
 40→function resolveOperand(
 41→  operand: SDUIExpressionOperand,
 42→  context: SDUIContext,
 43→  depth: number,
 44→): SDUILogicPrimitive {
 45→  if (isPrimitive(operand)) return operand;
 46→  if (isVarOperator(operand)) {
 47→    const resolved = resolveContextPath(context, operand.var);
 48→    if (isPrimitive(resolved)) return resolved;
 49→    return null;
 50→  }
 51→  if (isArithmeticExpression(operand)) {
 52→    return computeArithmetic(operand, context, depth + 1);
 53→  }
 54→  return evaluate(operand as SDUIRule, context, depth + 1);
 55→}
 56→
 57→function toNumber(value: SDUILogicPrimitive): number | null {
 58→  if (typeof value === 'number') return value;
 59→  if (typeof value === 'string') {
 60→    const n = Number(value);
 61→    return Number.isFinite(n) ? n : null;
 62→  }
 63→  return null;
 64→}
 65→
 66→function computeArithmetic(
 67→  expr: SDUIArithmeticExpression,
 68→  context: SDUIContext,
 69→  depth: number,
 70→): number {
 71→  if (depth > MAX_DEPTH) return 0;
 72→
 73→  const keys = Object.keys(expr);
 74→  const operator = keys[0];
 75→  const operands = (expr as Record<string, unknown>)[operator];
 76→  if (!Array.isArray(operands) || operands.length === 0) return 0;
 77→
 78→  const resolved = operands.map(op =>
 79→    toNumber(resolveOperand(op as SDUIExpressionOperand, context, depth)),
 80→  );
 81→
 82→  if (resolved.some(v => v === null)) return 0;
 83→  const nums = resolved as number[];
 84→
 85→  switch (operator) {
 86→    case '+':
 87→      return nums.reduce((a, b) => a + b, 0);
 88→    case '-':
 89→      if (nums.length !== 2) return 0;
 90→      return nums[0] - nums[1];
 91→    case '*':
 92→      return nums.reduce((a, b) => a * b, 1);
 93→    case '/':
 94→      if (nums.length !== 2) return 0;
 95→      if (nums[1] === 0) return 0;
 96→      return nums[0] / nums[1];
 97→    case 'min':
 98→      return Math.min(...nums);
 99→    case 'max':
100→      return Math.max(...nums);
101→    default:
102→      return 0;
103→  }
104→}
105→
106→function evaluateComparison(
107→  operator: string,
108→  operands: [SDUIExpressionOperand, SDUIExpressionOperand],
109→  context: SDUIContext,
110→  depth: number,
111→): boolean {
112→  const left = resolveOperand(operands[0], context, depth);
113→  const right = resolveOperand(operands[1], context, depth);
114→
115→  switch (operator) {
116→    case '==':
117→      return left == right; // eslint-disable-line eqeqeq
118→    case '!=':
119→      return left != right; // eslint-disable-line eqeqeq
120→    case '>':
121→      if (typeof left !== 'number' || typeof right !== 'number') return false;
122→      return left > right;
123→    case '<':
124→      if (typeof left !== 'number' || typeof right !== 'number') return false;
125→      return left < right;
126→    case '>=':
127→      if (typeof left !== 'number' || typeof right !== 'number') return false;
128→      return left >= right;
129→    case '<=':
130→      if (typeof left !== 'number' || typeof right !== 'number') return false;
131→      return left <= right;
132→    default:
133→      return false;
134→  }
135→}
136→
137→function evaluate(rule: SDUIRule, context: SDUIContext, depth: number): boolean {
138→  if (!rule || typeof rule !== 'object') return false;
139→  if (depth > MAX_DEPTH) return false;
140→
141→  const keys = Object.keys(rule);
142→  if (keys.length === 0) return false;
143→
144→  const operator = keys[0];
145→  const operands = (rule as Record<string, unknown>)[operator];
146→
147→  if (operator === 'and') {
148→    if (!Array.isArray(operands)) return false;
149→    return (operands as SDUIRule[]).every(sub => evaluate(sub, context, depth + 1));
150→  }
151→
152→  if (operator === 'or') {
153→    if (!Array.isArray(operands)) return false;
154→    return (operands as SDUIRule[]).some(sub => evaluate(sub, context, depth + 1));
155→  }
156→
157→  if (operator === '!') {
158→    const inner = Array.isArray(operands) ? operands[0] : operands;
159→    return !evaluate(inner as SDUIRule, context, depth + 1);
160→  }
161→
162→  if (COMPARISON_OPS.has(operator)) {
163→    if (!Array.isArray(operands) || operands.length !== 2) return false;
164→    return evaluateComparison(
165→      operator,
166→      operands as [SDUIExpressionOperand, SDUIExpressionOperand],
167→      context,
168→      depth,
169→    );
170→  }
171→
172→  return false;
173→}
174→
175→export function evaluateRule(rule: SDUIRule, context: SDUIContext): boolean {
176→  return evaluate(rule, context, 0);
177→}
178→
179→export function evaluateExpression(
180→  expr: SDUIArithmeticExpression | SDUIExpressionOperand,
181→  context: SDUIContext,
182→): number | string | boolean | null {
183→  if (isPrimitive(expr)) return expr;
184→  if (isVarOperator(expr)) {
185→    const resolved = resolveContextPath(context, expr.var);
186→    if (isPrimitive(resolved)) return resolved;
187→    return null;
188→  }
189→  if (isArithmeticExpression(expr)) {
190→    return computeArithmetic(expr, context, 0);
191→  }
192→  return evaluate(expr as SDUIRule, context, 0);
193→}
