  3→// ---------------------------------------------------------------------------
  4→// SDUI — Server Driven UI Type System
  5→// RFC: .claude/rfc-conteudo-dinamico.txt
  6→// ---------------------------------------------------------------------------
  7→
  8→// ---- 3.4  Context & Interpolation ----------------------------------------
  9→
 10→export type SDUIContextValue =
 11→  | string
 12→  | number
 13→  | boolean
 14→  | null
 15→  | SDUIContext
 16→  | SDUIContextValue[];
 17→
 18→export interface SDUIContext {
 19→  [key: string]: SDUIContextValue;
 20→}
 21→
 22→// ---- 3.5  JSON Logic (subset) --------------------------------------------
 23→
 24→/**
 25→ * Accesses a value from the context using dot notation.
 26→ * @example { var: 'balance.pointsFormatted' }
 27→ */
 28→export interface SDUIVarOperator {
 29→  var: string;
 30→}
 31→
 32→export type SDUILogicPrimitive = string | number | boolean | null;
 33→export type SDUILogicOperand = SDUIVarOperator | SDUILogicPrimitive | SDUIRule | SDUIArithmeticExpression;
 34→
 35→export interface SDUIComparisonRule {
 36→  '=='?: [SDUILogicOperand, SDUILogicOperand];
 37→  '!='?: [SDUILogicOperand, SDUILogicOperand];
 38→  '>'?: [SDUILogicOperand, SDUILogicOperand];
 39→  '<'?: [SDUILogicOperand, SDUILogicOperand];
 40→  '>='?: [SDUILogicOperand, SDUILogicOperand];
 41→  '<='?: [SDUILogicOperand, SDUILogicOperand];
 42→}
 43→
 44→export interface SDUILogicalRule {
 45→  and?: SDUIRule[];
 46→  or?: SDUIRule[];
 47→  '!'?: SDUIRule;
 48→}
 49→
 50→export type SDUIRule = SDUIComparisonRule | SDUILogicalRule;
 51→
 52→export interface SDUIArithmeticExpression {
 53→  '+'?: SDUIExpressionOperand[];
 54→  '-'?: [SDUIExpressionOperand, SDUIExpressionOperand];
 55→  '*'?: SDUIExpressionOperand[];
 56→  '/'?: [SDUIExpressionOperand, SDUIExpressionOperand];
 57→  min?: SDUIExpressionOperand[];
 58→  max?: SDUIExpressionOperand[];
 59→}
 60→
 61→export type SDUIExpressionOperand =
 62→  | SDUIVarOperator
 63→  | SDUILogicPrimitive
 64→  | SDUIArithmeticExpression
 65→  | SDUIRule;
 66→
 67→/**
 68→ * A boolean value computed from a JSON Logic rule.
 69→ * Used for visibility, enabled state, or any boolean prop.
 70→ * @example { rule: { '>': [{ var: 'form.points' }, 0] } }
 71→ */
 72→export interface SDUIConditional {
 73→  rule: SDUIRule;
 74→}
 75→
 76→export interface SDUIValidationRule {
 77→  rule: SDUIRule;
 78→  message: string;
 79→}
 80→
 81→export interface SDUIValidation {
 82→  rules: SDUIValidationRule[];
 83→}
 84→
